import{_ as t,c as r,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Regelerstellung: React Best Practices | Agent Skills","description":"Lernen Sie das Verfassen von Regeldateien, die den Spezifikationen entsprechen. Verwenden Sie _template.md und validieren Sie die Regelvollständigkeit durch pnpm validate.","frontmatter":{"title":"Regelerstellung: React Best Practices | Agent Skills","sidebarTitle":"Regelerstellung","subtitle":"Regelerstellung: React Best Practices","description":"Lernen Sie das Verfassen von Regeldateien, die den Spezifikationen entsprechen. Verwenden Sie _template.md und validieren Sie die Regelvollständigkeit durch pnpm validate.","tags":["Regelerstellung","React","Best Practices"],"prerequisite":["start-getting-started"]},"headers":[],"relativePath":"de/vercel-labs/agent-skills/advanced/rule-authoring/index.md","filePath":"de/vercel-labs/agent-skills/advanced/rule-authoring/index.md"}'),a={name:"de/vercel-labs/agent-skills/advanced/rule-authoring/index.md"};function l(s,e,d,c,o,h){return i(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="erstellen-von-react-best-practices-regeln" tabindex="-1">Erstellen von React Best Practices Regeln <a class="header-anchor" href="#erstellen-von-react-best-practices-regeln" aria-label="Permalink to &quot;Erstellen von React Best Practices Regeln&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Regeln für die React-Performance-Optimierung erstellen, die den Spezifikationen von Agent Skills entsprechen</li><li>Das _template.md-Template verwenden, um schnell Regeldateien zu erstellen</li><li>Korrekte Auswahl von Impact-Levels (CRITICAL/HIGH/MEDIUM) zur Klassifizierung von Regeln</li><li>Klare und verständliche Incorrect/Correct-Codevergleichsbeispiele schreiben</li><li>Validierung der Regelvollständigkeit durch <code>pnpm validate</code></li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Regeldateien sind im Markdown-Format und folgen einer <strong>dreiteiligen Struktur</strong>:</p><ol><li><strong>Frontmatter</strong>: Metadaten der Regel (title, impact, tags)</li><li><strong>Hauptüberschrift</strong>: Anzeigename der Regel und Impact-Erklärung</li><li><strong>Codebeispiele</strong>: <code>**Incorrect:**</code> und <code>**Correct:**</code> Vergleichsansicht</li></ol><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-vorlagedatei-kopieren" tabindex="-1">Schritt 1: Vorlagedatei kopieren <a class="header-anchor" href="#schritt-1-vorlagedatei-kopieren" aria-label="Permalink to &quot;Schritt 1: Vorlagedatei kopieren&quot;">​</a></h3><p>Verwenden Sie die Vorlage, um sicherzustellen, dass das Format korrekt ist und keine Pflichtfelder fehlen.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills/react-best-practices/rules</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _template.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-new-rule.md</span></span></code></pre></div><h3 id="schritt-2-frontmatter-metadaten-schreiben" tabindex="-1">Schritt 2: Frontmatter-Metadaten schreiben <a class="header-anchor" href="#schritt-2-frontmatter-metadaten-schreiben" aria-label="Permalink to &quot;Schritt 2: Frontmatter-Metadaten schreiben&quot;">​</a></h3><p>Die Frontmatter definiert den Titel, den Impact-Level und die Klassifizierungs-Tags der Regel.</p><h3 id="schritt-3-hauptuberschrift-und-erklarung-schreiben" tabindex="-1">Schritt 3: Hauptüberschrift und Erklärung schreiben <a class="header-anchor" href="#schritt-3-hauptuberschrift-und-erklarung-schreiben" aria-label="Permalink to &quot;Schritt 3: Hauptüberschrift und Erklärung schreiben&quot;">​</a></h3><p>Die Hauptüberschrift wird in der endgültigen Dokumentation angezeigt, die Erklärung hilft den Benutzern, die Bedeutung der Regel zu verstehen.</p><h3 id="schritt-4-incorrect-und-correct-beispiele-schreiben" tabindex="-1">Schritt 4: Incorrect- und Correct-Beispiele schreiben <a class="header-anchor" href="#schritt-4-incorrect-und-correct-beispiele-schreiben" aria-label="Permalink to &quot;Schritt 4: Incorrect- und Correct-Beispiele schreiben&quot;">​</a></h3><p>Vergleichsbeispiele sind der Kern der Regel, zeigen direkt &quot;Problemcode&quot; und &quot;korrekte Vorgehensweise&quot;.</p><h3 id="schritt-5-referenzen-hinzufugen-optional" tabindex="-1">Schritt 5: Referenzen hinzufügen (optional) <a class="header-anchor" href="#schritt-5-referenzen-hinzufugen-optional" aria-label="Permalink to &quot;Schritt 5: Referenzen hinzufügen (optional)&quot;">​</a></h3><p>Referenzen bieten der Regel autoritative Quellen und erhöhen die Glaubwürdigkeit.</p><h3 id="schritt-6-regeldatei-validieren" tabindex="-1">Schritt 6: Regeldatei validieren <a class="header-anchor" href="#schritt-6-regeldatei-validieren" aria-label="Permalink to &quot;Schritt 6: Regeldatei validieren&quot;">​</a></h3><p><code>pnpm validate</code> prüft die Vollständigkeit der Regel und stellt sicher, dass sie korrekt geparst werden kann.</p><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Regelerstellung folgt einem <strong>template-gesteuerten</strong> Ansatz, der Kernpunkte sind:</p><ol><li><strong>Frontmatter</strong> definiert Metadaten (title, impact, tags)</li><li><strong>Hauptteil</strong> enthält Überschrift, Impact-Erklärung und Codebeispiele</li><li><strong>Beispiele</strong> verwenden <code>**Incorrect:**</code>- und <code>**Correct:**</code>-Tags</li><li><strong>Validierung</strong> stellt durch <code>pnpm validate</code> die Formatkorrektheit sicher</li></ol><p><strong>5 Kernpunkte, die Sie sich merken sollten</strong>:</p><ul><li>✅ Verwenden Sie <code>_template.md</code> als Ausgangspunkt</li><li>✅ Impact-Levels verwenden Sie GROSSBUCHSTABEN (CRITICAL/HIGH/MEDIUM)</li><li>✅ Dateinamenpräfix bestimmt die Kapitelzuordnung (async-/bundle-/rerender- usw.)</li><li>✅ Beispiel-Label-Format: <code>**Incorrect (Beschreibung):**</code></li><li>✅ Führen Sie vor dem Commit <code>pnpm validate</code> aus</li></ul><hr><h2 id="anhang-quellcodereferenz" tabindex="-1">Anhang: Quellcodereferenz <a class="header-anchor" href="#anhang-quellcodereferenz" aria-label="Permalink to &quot;Anhang: Quellcodereferenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcodepositionen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Regelvorlagedatei</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/react-best-practices/rules/_template.md" target="_blank" rel="noreferrer"><code>skills/react-best-practices/rules/_template.md</code></a></td><td>1-29</td></tr><tr><td>Regeltypendefinition</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/src/types.ts" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/src/types.ts</code></a></td><td>5-26</td></tr><tr><td>Regelvalidierungslogik</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/src/validate.ts" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/src/validate.ts</code></a></td><td>21-66</td></tr></tbody></table><p><strong>Validierungsregeln</strong>:</p><ul><li>Titel nicht leer</li><li>Anzahl der examples ≥ 1</li><li>Impact muss ein gültiger Enum-Wert sein</li></ul><p><strong>Kapitel-Mapping</strong> (Dateinamenpräfix → Kapitel → Level):</p><table tabindex="0"><thead><tr><th>Dateipräfix</th><th>Kapitelnummer</th><th>Kapiteltitel</th><th>Standard-Level</th></tr></thead><tbody><tr><td><code>async-</code></td><td>1</td><td>Beseitigung von Waterfalls</td><td>CRITICAL</td></tr><tr><td><code>bundle-</code></td><td>2</td><td>Bundle-Optimierung</td><td>CRITICAL</td></tr></tbody></table></details>`,28)])])}const p=t(a,[["render",l]]);export{g as __pageData,p as default};
